class Solution:
    def averageOfLevels(self, root: Optional[TreeNode]) -> List[float]:
        if not root: return []
        q=[root]; ans=[]
        while q:
            nxt=[]; s=c=0
            for node in q:
                s+=node.val; c+=1
                if node.left: nxt.append(node.left)
                if node.right: nxt.append(node.right)
            ans.append(s/c); q=nxt
        return ans

