class Solution {
public:
    vector<double> averageOfLevels(TreeNode* root) {
        vector<double> ans; if(!root) return ans;
        queue<TreeNode*> q; q.push(root);
        while(!q.empty()){
            int sz=q.size(); double s=0;
            for(int i=0;i<sz;i++){
                auto* n=q.front(); q.pop(); s+=n->val;
                if(n->left) q.push(n->left); if(n->right) q.push(n->right);
            }
            ans.push_back(s/sz);
        }
        return ans;
    }
};

