double* averageOfLevels637(struct TreeNode* root,int* rs) {
    if(!root){ *rs=0; return NULL; }
    struct TreeNode** q=malloc(10000*sizeof(*q)); int ql=0,qr=0;
    double* ans=malloc(1000*sizeof(double)); *rs=0;
    q[qr++]=root;
    while(ql<qr){
        int sz=qr-ql; double s=0;
        for(int i=0;i<sz;i++){
            struct TreeNode* n=q[ql++]; s+=n->val;
            if(n->left) q[qr++]=n->left;
            if(n->right) q[qr++]=n->right;
        }
        ans[(*rs)++]=s/sz;
    }
    free(q); return ans;
}
